mapper.select:
SELECT id ,name ,password ,manager ,contact ,conManager ,conContact , date_format(createDate, '%Y-%m-%d') as createDate ,location ,role ,userId ,address ,isDel ,groupIdx ,secretCode ,conduct ,fcIdx ,longCalYn ,ubcYn ,originDataYn ,showPdfYn
FROM TB_CONSTRUCTION
ORDER BY (case when id = 1 then 10000 else (case when id = 587 then 9999 else 0 end) end ) desc , conduct ASC, id DESC LIMIT #{pageSize} OFFSET #{startRow}

SELECT id ,name ,manager ,password ,contact ,conManager ,conContact , date_format(createDate, '%Y-%m-%d') as createDate ,location ,role ,userId ,address ,isDel ,groupIdx ,secretCode ,conduct ,fcIdx ,longCalYn ,ubcYn ,originDataYn ,showPdfYn
FROM TB_CONSTRUCTION
ORDER BY (case when id = 1 then 10000 else (case when id = 587 then 9999 else 0 end) end ) desc , conduct ASC, id DESC LIMIT #{pageSize} OFFSET #{startRow}

mapper.update:
	    UPDATE 
	    	TB_CONSTRUCTION 
	    SET 
	    	name = #{name} , 
	    	location = #{location} ,
	    	address = #{address},
	    	manager = #{manager} 

	    	, password = #{password} 

	    	, contact = #{contact} 
	    	, conManager = #{conManager} 
	    	, conContact = #{conContact} 
	    	, groupIdx = #{groupIdx} 
	    	, secretCode = #{secretCode} 
	    	, fcIdx = #{fcIdx} 
	    	, longCalYn = #{longCalYn} 
    		, ubcYn = #{ubcYn}
    		, originDataYn  = #{originDataYn}
    		, showPdfYn  = #{showPdfYn}

	    WHERE id = #{id}
